class Solution:
    def numberOfBeautifulIntegers(self, low: int, high: int, k: int) -> int:
        count = 0
        for num in range(low, high + 1):
            if num % k != 0:
                continue
            even_count = 0
            odd_count = 0
            for digit in str(num):
                if int(digit) % 2 == 0:
                    even_count += 1
                else:
                    odd_count += 1
            if even_count == odd_count:
                count += 1
        return count
